                    <h2 id="endpoints-POSTapi-tenants-register">POST api/tenants/register</h2>

<p>
</p>



<span id="example-requests-POSTapi-tenants-register">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://127.0.0.1:8000/api/tenants/register" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --header "X-Tenant-Id: {TENANT_SLUG}" \
    --data "{
    \"company_name\": \"b\",
    \"slug\": \"n\",
    \"admin_name\": \"g\",
    \"admin_email\": \"rowan.gulgowski@example.com\",
    \"password\": \"BNvYgxwmi\\/#iw\\/kX\",
    \"plan\": \"custom\",
    \"modules\": [
        \"architecto\"
    ],
    \"company_type\": \"General\",
    \"users_limit\": 22,
    \"start_date\": \"2026-04-04T18:25:12\",
    \"end_date\": \"2052-04-27\",
    \"is_lifetime\": true,
    \"country\": \"n\",
    \"address_line_1\": \"g\",
    \"city\": \"z\",
    \"state\": \"m\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/tenants/register"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
    "X-Tenant-Id": "{TENANT_SLUG}",
};

let body = {
    "company_name": "b",
    "slug": "n",
    "admin_name": "g",
    "admin_email": "rowan.gulgowski@example.com",
