body.append('created_by_name', 'architecto');
body.append('related_to', 'architecto');
body.append('related_ref', 'architecto');
body.append('progress', '16');
body.append('reminder_before', 'architecto');
body.append('recurring', 'architecto');
body.append('attachment', document.querySelector('input[name="attachment"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>

