<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://127.0.0.1:8000/api/admin/fields/architecto" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --header "X-Tenant-Id: {TENANT_SLUG}" \
    --data "{
    \"key\": \"b\",
    \"label_en\": \"n\",
    \"label_ar\": \"g\",
    \"placeholder_en\": \"z\",
    \"placeholder_ar\": \"m\",
    \"type\": \"email\",
    \"can_filter\": true,
    \"is_landing_page\": false,
    \"show_my_lead\": false,
    \"show_sales\": false,
    \"show_manager\": false,
    \"is_exportable\": false
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://127.0.0.1:8000/api/admin/fields/architecto"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
    "X-Tenant-Id": "{TENANT_SLUG}",
};

let body = {
    "key": "b",
    "label_en": "n",
    "label_ar": "g",
    "placeholder_en": "z",
    "placeholder_ar": "m",
    "type": "email",
    "can_filter": true,
    "is_landing_page": false,
    "show_my_lead": false,
    "show_sales": false,
    "show_manager": false,
    "is_exportable": false
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

